// ETAPE 4 — Conversion HTML → Markdown + Découpage en chunks
// Paramètres ajustables :
const MOTS_MAX = 500; // Taille max d'un chunk (augmenter pour plus de contexte)
const MOTS_MIN = 50;  // Taille min (ignorer les chunks trop courts)

const html = String($input.first().json.data || $input.first().json.body || '');
console.log('HTML recu, longueur:', html.length, 'caracteres');

// Conversion HTML basique vers Markdown
let md = html
  .replace(/<h1[^>]*>(.*?)<\/h1>/gi, '# $1\n\n')
  .replace(/<h2[^>]*>(.*?)<\/h2>/gi, '## $1\n\n')
  .replace(/<h3[^>]*>(.*?)<\/h3>/gi, '### $1\n\n')
  .replace(/<strong[^>]*>(.*?)<\/strong>/gi, '**$1**')
  .replace(/<b[^>]*>(.*?)<\/b>/gi, '**$1**')
  .replace(/<em[^>]*>(.*?)<\/em>/gi, '*$1*')
  .replace(/<li[^>]*>(.*?)<\/li>/gi, '- $1\n')
  .replace(/<p[^>]*>(.*?)<\/p>/gi, '$1\n\n')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

console.log('Markdown genere, longueur:', md.length, 'caracteres');

// Découpage en chunks par titres H1/H2 ou par limite de mots
const sections = [];
const lines = md.split('\n');
let chunk = [];
let titre = 'Introduction';
let mots = 0;
let idx = 0;

for (const line of lines) {
  const isTitle = line.startsWith('# ') || line.startsWith('## ');
  if (isTitle && chunk.length > 0) {
    const content = chunk.join('\n').trim();
    const w = content.split(/\s+/).length;
    if (w >= MOTS_MIN) {
      idx++;
      sections.push({ index: idx, titre, contenu: content, mots: w });
      console.log('Chunk', idx, ':', titre, '-', w, 'mots');
    }
    titre = line.replace(/^#+\s/, '').trim();
    chunk = [line];
    mots = 0;
  } else {
    chunk.push(line);
    mots += line.split(/\s+/).filter(w => w.length > 0).length;
    if (mots >= MOTS_MAX) {
      idx++;
      sections.push({ index: idx, titre: titre + ' (suite)', contenu: chunk.join('\n').trim(), mots });
      chunk = [];
      mots = 0;
    }
  }
}

if (chunk.length > 0) {
  const content = chunk.join('\n').trim();
  const w = content.split(/\s+/).length;
  if (w >= MOTS_MIN) { idx++; sections.push({ index: idx, titre, contenu: content, mots: w }); }
}

console.log('TOTAL chunks generes:', sections.length);
return sections.map(s => ({ json: s }));

// ETAPE 6 — Préparation du payload pour Flowise
// Parse la réponse DeepSeek et assemble le payload

const response = $input.first().json;
const chunk = $('HTML vers Markdown et Chunks').first().json;

// Parse les métadonnées DeepSeek
let meta = {};
try {
  const content = response.choices[0].message.content;
  const cleaned = content.replace(/```json|```/g, '').trim();
  meta = JSON.parse(cleaned);
  console.log('Metadonnees parsees:', JSON.stringify(meta));
} catch(e) {
  // Fallback si parsing échoue
  console.log('Fallback metadonnees generiques');
  meta = { module: 'general', difficulte: 'debutant', type: 'principe', tags: ['mlm'], resume: chunk.titre };
}

// Assemble le payload final
return [{ json: {
  text: chunk.contenu,
  metadata: {
    ...meta,
    titre: chunk.titre,
    chunk_index: chunk.index,
    mots: chunk.mots,
    langue: 'fr',
    source: 'big_al',
    indexed_at: new Date().toISOString()
  }
}}];
